create policy "tenant_isolation"
  on "public"."news_badges_relations"
  as permissive
  for all
  to public
using ((tenant_id = ((( SELECT current_setting('request.headers'::text, true) AS current_setting))::json ->> 'x-tenant-id'::text)));

INSERT INTO public.news_badges_relations (news_id, profile_badge_id, tenant_id)
SELECT id, profile_badge, tenant_id
FROM public.news
WHERE profile_badge IS NOT NULL;